import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import styles from '../../styles/erpPage.module.css';
import type { UseCatalogListSelectionResult } from '../../hooks/useCatalogListSelection';
import {
  DEFAULT_CATALOG_LIST_TABLE_CONFIG,
  parseCatalogColumnWidthPx,
  type CatalogListTableConfig,
} from './catalogListTableConfig';

export type CatalogListColumnDef = {
  key: string;
  label?: React.ReactNode;
  width?: string | null;
};

export interface CatalogListGridProps<T> {
  testIdPrefix: string;
  rows: T[];
  page: number;
  pageSize: number;
  selection: UseCatalogListSelectionResult<T>;
  isRowSelectable?: (row: T) => boolean;
  getRowId: (row: T) => string;
  /** Extra columns after STT + checkbox */
  headerCells: React.ReactNode;
  renderRow: (row: T, rowNo: number) => React.ReactNode;
  /** Width / resize — parallel to headerCells data columns */
  columnDefs?: CatalogListColumnDef[];
  tableConfig?: Partial<CatalogListTableConfig>;
}

const COL_NO_PX = 48;
const COL_CHECK_PX = 40;
const DEFAULT_DATA_COL_PX = 120;
const MIN_DATA_COL_PX = 64;

function buildInitialColWidths(
  columnDefs: CatalogListColumnDef[] | undefined,
  resizable: boolean,
): number[] {
  if (!columnDefs?.length) return [];
  return columnDefs.map(col => {
    const parsed = parseCatalogColumnWidthPx(col.width);
    if (parsed != null) return Math.max(MIN_DATA_COL_PX, parsed);
    if (!resizable && col.width) return DEFAULT_DATA_COL_PX;
    return DEFAULT_DATA_COL_PX;
  });
}

/** Grid danh mục — STT + checkbox (batch) + click row → active (toolbar). */
export function CatalogListGrid<T>({
  testIdPrefix,
  rows,
  page,
  pageSize,
  selection,
  isRowSelectable = () => true,
  getRowId,
  headerCells,
  renderRow,
  columnDefs,
  tableConfig: tableConfigPartial,
}: CatalogListGridProps<T>): React.ReactElement {
  const tableConfig = useMemo(
    () => ({ ...DEFAULT_CATALOG_LIST_TABLE_CONFIG, ...tableConfigPartial }),
    [tableConfigPartial],
  );

  const storageKey = `${testIdPrefix}-col-widths`;
  const [colWidths, setColWidths] = useState<number[]>(() => {
    const initial = buildInitialColWidths(columnDefs, tableConfig.resizable);
    if (!tableConfig.resizable || typeof window === 'undefined') return initial;
    try {
      const raw = localStorage.getItem(storageKey);
      if (!raw) return initial;
      const parsed = JSON.parse(raw) as number[];
      if (Array.isArray(parsed) && parsed.length === initial.length) return parsed;
    } catch {
      /* ignore */
    }
    return initial;
  });

  useEffect(() => {
    setColWidths(buildInitialColWidths(columnDefs, tableConfig.resizable));
  }, [columnDefs, tableConfig.resizable]);

  useEffect(() => {
    if (!tableConfig.resizable || colWidths.length === 0) return;
    try {
      localStorage.setItem(storageKey, JSON.stringify(colWidths));
    } catch {
      /* ignore */
    }
  }, [colWidths, storageKey, tableConfig.resizable]);

  const resizeRef = useRef<{ index: number; startX: number; startW: number } | null>(null);

  const onResizePointerDown = useCallback((index: number, e: React.PointerEvent) => {
    e.preventDefault();
    e.stopPropagation();
    resizeRef.current = { index, startX: e.clientX, startW: colWidths[index] ?? DEFAULT_DATA_COL_PX };
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  }, [colWidths]);

  const onResizePointerMove = useCallback((e: React.PointerEvent) => {
    const r = resizeRef.current;
    if (r == null) return;
    const delta = e.clientX - r.startX;
    setColWidths(prev => {
      const next = [...prev];
      next[r.index] = Math.max(MIN_DATA_COL_PX, r.startW + delta);
      return next;
    });
  }, []);

  const onResizePointerUp = useCallback((e: React.PointerEvent) => {
    resizeRef.current = null;
    try {
      (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    } catch {
      /* ignore */
    }
  }, []);

  const selectableOnPage = rows.filter(isRowSelectable);

  const rowClassName = (row: T): string | undefined => {
    const active = selection.isRowActive(row);
    const checked = selection.isRowChecked(row);
    if (active && checked) return `${styles.catalogRowActive} ${styles.catalogRowChecked}`;
    if (active) return styles.catalogRowActive;
    if (checked) return styles.catalogRowChecked;
    return undefined;
  };

  const handleRowClick = (row: T, e: React.MouseEvent<HTMLTableRowElement>) => {
    const target = e.target as HTMLElement;
    if (target.closest('input, button, a, [role="button"]')) return;
    selection.selectActiveRow(row);
  };

  const useColgroup = Boolean(columnDefs?.length);
  const stickyHeader = tableConfig.stickyHeader;
  const wrapperClass = [
    styles.tableWrapper,
    stickyHeader ? styles.tableWrapperStickyHead : '',
    tableConfig.heightMode === 'fixed' ? styles.tableWrapperHeightFixed : '',
  ].filter(Boolean).join(' ');

  const wrapperStyle: React.CSSProperties | undefined =
    tableConfig.heightMode === 'fixed' && tableConfig.height
      ? { maxHeight: tableConfig.height, height: tableConfig.height }
      : undefined;

  const renderHeaderCells = () => {
    if (!columnDefs?.length) return headerCells;
    return columnDefs.map((col, i) => (
      <th
        key={col.key}
        className={tableConfig.resizable ? styles.tableThResizable : undefined}
        style={useColgroup && !tableConfig.resizable && col.width ? { width: col.width } : undefined}
      >
        {col.label ?? col.key}
        {tableConfig.resizable ? (
          <span
            className={styles.tableColResizeHandle}
            role="separator"
            aria-orientation="vertical"
            aria-label={`Đổi độ rộng cột ${col.label ?? col.key}`}
            onPointerDown={e => onResizePointerDown(i, e)}
            onPointerMove={onResizePointerMove}
            onPointerUp={onResizePointerUp}
            onPointerCancel={onResizePointerUp}
          />
        ) : null}
      </th>
    ));
  };

  return (
    <div className={wrapperClass} style={wrapperStyle} data-testid={`${testIdPrefix}-grid`}>
      <table
        className={[styles.table, useColgroup ? styles.tableLayoutFixed : ''].filter(Boolean).join(' ')}
      >
        {useColgroup ? (
          <colgroup>
            <col style={{ width: COL_NO_PX }} />
            <col style={{ width: COL_CHECK_PX }} />
            {columnDefs!.map((col, i) => (
              <col
                key={col.key}
                style={{
                  width: tableConfig.resizable
                    ? colWidths[i]
                    : col.width ?? undefined,
                }}
              />
            ))}
          </colgroup>
        ) : null}
        <thead>
          <tr>
            <th className={styles.colNo}>STT</th>
            <th className={styles.colCheck}>
              <input
                type="checkbox"
                data-testid={`${testIdPrefix}-select-all-page`}
                checked={selection.isPageAllSelected && selectableOnPage.length > 0}
                disabled={selectableOnPage.length === 0}
                aria-label="Chọn tất cả trên trang"
                onChange={selection.togglePageAll}
              />
            </th>
            {renderHeaderCells()}
          </tr>
        </thead>
        <tbody>
          {rows.map((row, index) => {
            const id = getRowId(row);
            const rowNo = (page - 1) * pageSize + index + 1;
            const selectable = isRowSelectable(row);
            const checked = selection.isRowChecked(row);
            return (
              <tr
                key={id}
                className={rowClassName(row)}
                data-testid={`${testIdPrefix}-row-${id}`}
                onClick={e => handleRowClick(row, e)}
              >
                <td className={styles.colNo} data-testid={`${testIdPrefix}-row-${id}-no`}>
                  {rowNo}
                </td>
                <td className={styles.colCheck} onClick={e => e.stopPropagation()}>
                  <input
                    type="checkbox"
                    data-testid={`${testIdPrefix}-row-${id}-select`}
                    checked={checked}
                    disabled={!selectable}
                    aria-label={`Chọn dòng ${rowNo}`}
                    onChange={e => selection.toggleRow(row, e.target.checked)}
                  />
                </td>
                {renderRow(row, rowNo)}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}
