import React, { useEffect, useState } from 'react';
import { Button, Modal, addToast } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';
import type { CodeUsageImpactRow } from './CatalogRenameCodeModal';

export type CatalogBatchDeleteMode = 'soft' | 'remove';

export interface CatalogBatchDeleteModalProps {
  testIdPrefix: string;
  isOpen: boolean;
  onClose: () => void;
  selectedCount: number;
  catalogKind: string;
  /** Preview usage for hard delete */
  fetchDeleteImpact?: (
    catalogKind: string,
    ids: string[],
    allMatchingFilter: boolean,
  ) => Promise<{ canRemove: boolean; impact: CodeUsageImpactRow[]; blockedReason?: string }>;
  onConfirm: (mode: CatalogBatchDeleteMode) => Promise<void>;
}

export const CatalogBatchDeleteModal: React.FC<CatalogBatchDeleteModalProps> = ({
  testIdPrefix,
  isOpen,
  onClose,
  selectedCount,
  catalogKind,
  fetchDeleteImpact,
  onConfirm,
}) => {
  const [mode, setMode] = useState<CatalogBatchDeleteMode>('soft');
  const [impact, setImpact] = useState<CodeUsageImpactRow[]>([]);
  const [canRemove, setCanRemove] = useState(true);
  const [blockedReason, setBlockedReason] = useState<string | undefined>();
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    setMode('soft');
    setImpact([]);
    setCanRemove(true);
    setBlockedReason(undefined);
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen || mode !== 'remove' || !fetchDeleteImpact) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      fetchDeleteImpact(catalogKind, [], false)
        .then(res => {
          if (cancelled) return;
          setImpact(res.impact);
          setCanRemove(res.canRemove);
          setBlockedReason(res.blockedReason);
        })
        .catch(() => {
          if (!cancelled) {
            setCanRemove(false);
            setBlockedReason('Không tải được thông tin ràng buộc');
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [isOpen, mode, catalogKind, fetchDeleteImpact]);

  const submit = async () => {
    if (mode === 'remove' && !canRemove) {
      addToast({ message: blockedReason ?? 'Không thể xóa vĩnh viễn — đang được sử dụng', type: 'error' });
      return;
    }
    setSubmitting(true);
    try {
      await onConfirm(mode);
      onClose();
    } catch (err: unknown) {
      addToast({
        message: err instanceof Error ? err.message : 'Xóa thất bại',
        type: 'error',
      });
    } finally {
      setSubmitting(false);
    }
  };

  const totalRefs = impact.reduce((s, r) => s + r.estimatedCount, 0);

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Xóa danh mục"
      size="md"
      data-testid={`${testIdPrefix}-batch-delete-modal`}
    >
      <div className={styles.catalogModalBody}>
        <p>Đang thao tác trên <strong>{selectedCount}</strong> bản ghi đã chọn.</p>
        <div className={styles.catalogDeleteModeTabs}>
          <button
            type="button"
            className={mode === 'soft' ? styles.sharedProposalTabActive : styles.sharedProposalTab}
            onClick={() => setMode('soft')}
          >
            Ngưng sử dụng (soft)
          </button>
          <button
            type="button"
            className={mode === 'remove' ? styles.sharedProposalTabActive : styles.sharedProposalTab}
            onClick={() => setMode('remove')}
          >
            Xóa vĩnh viễn
          </button>
        </div>
        {mode === 'soft' && (
          <div className={styles.catalogInfoBanner}>
            Tạm ẩn khỏi danh sách mặc định — vẫn xem được phát sinh / lịch sử. Có thể bật lại bằng «Đang sử dụng».
          </div>
        )}
        {mode === 'remove' && (
          <>
            <div className={styles.catalogWarningBanner}>
              Không thể hoàn tác. Chỉ xóa khi không còn chứng từ/danh mục tham chiếu.
            </div>
            {loading ? (
              <p className={styles.sharedCatalogHint}>Đang kiểm tra ràng buộc…</p>
            ) : !canRemove ? (
              <div className={styles.catalogRiskBlock}>
                <p><strong>Không thể xóa</strong> — {blockedReason ?? `Còn ${totalRefs} tham chiếu trong hệ thống.`}</p>
                {impact.length > 0 && (
                  <ul>
                    {impact.map(row => (
                      <li key={row.tableName}>
                        {row.entityLabel}: <strong>{row.estimatedCount}</strong>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            ) : (
              <div className={styles.catalogSafeBlock}>
                <i className="fas fa-check-circle" /> An toàn — không phát hiện tham chiếu đang sử dụng.
              </div>
            )}
          </>
        )}
      </div>
      <div className={styles.modalFooterBar}>
        <Button variant="secondary" onClick={onClose} disabled={submitting}>Hủy</Button>
        <Button
          variant={mode === 'remove' ? 'danger' : 'primary'}
          disabled={submitting || (mode === 'remove' && !canRemove)}
          data-testid={`${testIdPrefix}-batch-delete-confirm`}
          onClick={() => void submit()}
        >
          {submitting ? 'Đang xử lý…' : mode === 'soft' ? 'Ngưng sử dụng' : 'Xóa vĩnh viễn'}
        </Button>
      </div>
    </Modal>
  );
};
