import React from 'react';
import { Link, Outlet, useLocation } from 'react-router-dom';
import { useResponsive } from '@linm-soft/common-components';
import { showDevNav, isStandalone } from '../../../dev/isStandalone';
import { isCatalogListPath } from '../../../utils/isCatalogListPath';
import styles from './AppLayout.module.css';

const getPageTitle = (pathname: string): string => {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/dm')) return 'Danh Mục';
  if (pathname.startsWith('/system')) return 'Hệ Thống';
  return 'ERP Danh Mục';
};

export const AppLayout: React.FC = () => {
  const location = useLocation();
  const { isMobile } = useResponsive();
  const title = getPageTitle(location.pathname);
  const catalogListShell = isCatalogListPath(location.pathname);

  return (
    <div
      className={[
        styles.main,
        isStandalone ? styles.mainStandalone : styles.mainEmbedded,
      ].filter(Boolean).join(' ')}
      data-modal-root
    >
      {isStandalone && (
        <header className={styles.topbar}>
          <div className={styles.topbarLeft}>
            {isMobile && (
              <button
                type="button"
                className={styles.menuButton}
                onClick={() => window.dispatchEvent(new CustomEvent('linm:nav:toggle-mobile'))}
                aria-label="Mở menu"
              >
                <i className="fas fa-bars" />
              </button>
            )}
            <h1 className={styles.title}>{title}</h1>
          </div>
          {showDevNav && !location.pathname.startsWith('/dev') && (
            <Link to="/dev" className={styles.devLink} title="Dev Navigation">
              <i className="fas fa-wrench" aria-hidden />
            </Link>
          )}
        </header>
      )}
      <div
        className={[
          styles.content,
          catalogListShell ? styles.contentCatalogListShell : '',
        ].filter(Boolean).join(' ')}
      >
        <Outlet />
      </div>
    </div>
  );
};

export default AppLayout;
